import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useState } from 'react';

export function useParentDashboardLearner() {
  const { copy } = useKangurMobileI18n();
  const { session } = useKangurMobileAuth();
  const [selectionError, setSelectionError] = useState<string | null>(null);
  const [switchingLearnerId, setSwitchingLearnerId] = useState<string | null>(null);

  const activeLearner = session.user?.activeLearner ?? null;
  const selectedLearnerId = activeLearner?.id.trim() ?? null;
  const learners = session.user?.learners ?? [];

  const trimmedFullName = session.user?.full_name?.trim();
  const parentDisplayName =
    typeof trimmedFullName === 'string' && trimmedFullName !== ''
      ? trimmedFullName
      : copy({
          de: 'Elternkonto',
          en: 'Parent account',
          pl: 'Konto rodzica',
        });

  return {
    activeLearner,
    selectedLearnerId,
    learners,
    parentDisplayName,
    selectionError,
    switchingLearnerId,
    setSelectionError,
    setSwitchingLearnerId
  };
}

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { type KangurProgressState } from '@kangur/contracts/kangur';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { buildKangurLearnerProfileSnapshot } from '@kangur/core';
import { createDefaultKangurProgressState } from '@kangur/contracts/kangur';

export function useParentDashboardProgress(
  canAccessDashboard: boolean,
  selectedLearnerId: string | null,
  recentResultsScores: any[],
  locale: any,
) {
  const { apiBaseUrl, apiClient, defaultDailyGoalGames } = useKangurMobileRuntime();

  const progressQuery = useQuery({
    enabled: canAccessDashboard && selectedLearnerId !== null,
    queryKey: ['kangur-mobile', 'parent-dashboard', 'progress', apiBaseUrl, selectedLearnerId ?? 'none'],
    queryFn: async (): Promise<KangurProgressState> => apiClient.getProgress(undefined, { cache: 'no-store' }),
    staleTime: 30_000,
  });

  const snapshot = useMemo(() => {
    if (!canAccessDashboard || selectedLearnerId === null) return null;
    return buildKangurLearnerProfileSnapshot({
      dailyGoalGames: defaultDailyGoalGames,
      locale,
      progress: progressQuery.data ?? createDefaultKangurProgressState(),
      scores: recentResultsScores,
    });
  }, [canAccessDashboard, defaultDailyGoalGames, locale, progressQuery.data, recentResultsScores, selectedLearnerId]);

  return { progressQuery, snapshot };
}

import { useMemo } from 'react';
import { createKangurLessonHrefForPracticeOperation } from '../lessons/lessonHref';
import { createKangurPracticeHref } from '../practice/practiceHref';
import { createKangurResultsHref } from '../scores/resultsHref';
import { type KangurMobileParentRecentResultItem } from './parent-dashboard-types';

export function useParentDashboardResults(recentResults: { scores: any[] }) {
  return useMemo(
    (): KangurMobileParentRecentResultItem[] =>
      recentResults.scores.map((result) => ({
        historyHref: createKangurResultsHref({ operation: result.operation }),
        lessonHref: createKangurLessonHrefForPracticeOperation(result.operation),
        practiceHref: createKangurPracticeHref(result.operation),
        result,
      })),
    [recentResults.scores],
  );
}
